# --- Duplicate Detection ---

class TransactionDeduplicator:
    """Simple in-memory deduplication. In production, use Redis or a database."""

    def __init__(self, max_size: int = 100000):
        self._seen: dict[str, datetime] = {}
        self._max_size = max_size

    def is_duplicate(self, transaction_id: str) -> bool:
        if transaction_id in self._seen:
            logger.warning("Duplicate transaction detected: %s", transaction_id)
            return True
        if len(self._seen) >= self._max_size:
            # Evict oldest entries
            cutoff = len(self._seen) // 2
            sorted_keys = sorted(self._seen, key=self._seen.get)
            for key in sorted_keys[:cutoff]:
                del self._seen[key]
        self._seen[transaction_id] = datetime.now(timezone.utc)
        return False


